-- ============================================================================
-- ALIGNMENT GYM LAUNCH EMAIL
--
-- Personal-style announcement email for the Alignment Gym weekly sessions.
-- Manual CRM blast to existing members. Not branded — reads like a personal
-- email from Jordan & Vanessa.
-- ============================================================================

INSERT INTO email_templates (slug, name, description, category, status, subject, html_body, text_body, variables, triggers)
VALUES (
  'alignment-gym-launch',
  'Alignment Gym: Launch Announcement',
  'Personal email announcing the weekly Alignment Gym sessions starting March 31. Manual CRM blast to existing members.',
  'marketing',
  'active',

  -- SUBJECT
  E'Something new starts Tuesday',

  -- HTML BODY (personal style — no branded cards/badges)
  E'<!DOCTYPE html>\n<html lang="en">\n<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>\n<body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#ffffff;color:#333333;">\n<table width="100%" cellpadding="0" cellspacing="0" style="background-color:#ffffff;"><tr><td align="center" style="padding:40px 20px;">\n<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;text-align:left;">\n<tr><td style="font-size:16px;line-height:1.7;color:#333333;">\n\n<p style="margin:0 0 16px;">Hi {{firstName}},</p>\n\n<p style="margin:0 0 16px;">This Tuesday, March 31st, we''re opening something brand new inside Vibration Fit:</p>\n\n<p style="margin:0 0 16px;font-size:18px;"><strong>The Alignment Gym.</strong></p>\n\n<p style="margin:0 0 8px;">This is our weekly live space to:</p>\n<ul style="margin:0 0 16px;padding-left:24px;">\n  <li style="margin-bottom:4px;">Strengthen and clarify your vision</li>\n  <li style="margin-bottom:4px;">Practice getting into vibrational harmony on purpose</li>\n  <li style="margin-bottom:4px;">Get coaching and community support so your vision becomes real, not just &ldquo;someday&rdquo;</li>\n</ul>\n\n<p style="margin:0 0 12px;font-size:17px;"><strong>When &amp; where</strong></p>\n<p style="margin:0 0 4px;">Every Tuesday at 12 pm ET</p>\n<p style="margin:0 0 4px;">First session: Tuesday, March 31st</p>\n<p style="margin:0 0 16px;">Log in and join the session at: <a href="https://vibrationfit.com/alignment-gym" style="color:#1a73e8;text-decoration:none;">vibrationfit.com/alignment-gym</a></p>\n\n<p style="margin:0 0 16px;">Put this on your calendar as a recurring Tuesday lunch appointment and mark it &ldquo;Busy.&rdquo; Treat it like a non&#8209;negotiable lunch with your future self.</p>\n\n<p style="margin:0 0 12px;font-size:17px;"><strong>Who the Alignment Gym is for</strong></p>\n<p style="margin:0 0 16px;">The Alignment Gym is designed for members who have completed the Intensive, because we''ll be using those tools live, not reteaching them.</p>\n\n<p style="margin:0 0 8px;"><strong>If you''ve already finished the Intensive:</strong></p>\n<ul style="margin:0 0 16px;padding-left:24px;">\n  <li style="margin-bottom:4px;">Add the Alignment Gym to your calendar</li>\n  <li style="margin-bottom:4px;">Plan to be there live this Tuesday at 12 pm ET</li>\n  <li style="margin-bottom:4px;">Bring your vision and anything you''re currently creating</li>\n</ul>\n\n<p style="margin:0 0 8px;"><strong>If you haven''t finished the Intensive yet:</strong></p>\n<p style="margin:0 0 16px;">You still have time to finish.</p>\n<p style="margin:0 0 16px;">Log in here: <a href="https://vibrationfit.com/auth/login" style="color:#1a73e8;text-decoration:none;">vibrationfit.com/auth/login</a></p>\n<p style="margin:0 0 16px;">When you complete the Intensive, you''ll be fully prepared to get the most from each Alignment Gym session.</p>\n<p style="margin:0 0 16px;">Think of the Intensive as your foundation and the Alignment Gym as your weekly practice. The more solid your foundation, the more powerfully you can use this space.</p>\n\n<p style="margin:0 0 12px;font-size:17px;"><strong>Why this matters</strong></p>\n<p style="margin:0 0 16px;">Most people consume spiritual content and still feel stuck.</p>\n<p style="margin:0 0 4px;">The Intensive gives you the framework.</p>\n<p style="margin:0 0 16px;">The Alignment Gym gives you the reps.</p>\n\n<p style="margin:0 0 8px;">If you want this next season of your life to actually look different, start by:</p>\n<ol style="margin:0 0 16px;padding-left:24px;">\n  <li style="margin-bottom:4px;">Finishing your Intensive, and</li>\n  <li style="margin-bottom:4px;">Showing up live on Tuesday at 12 pm ET.</li>\n</ol>\n\n<p style="margin:0 0 4px;">See you in the Alignment Gym,</p>\n<p style="margin:0;">Jordan &amp; Vanessa</p>\n\n</td></tr>\n</table></td></tr></table>\n</body></html>',

  -- TEXT BODY
  E'Hi {{firstName}},\n\nThis Tuesday, March 31st, we''re opening something brand new inside Vibration Fit:\n\nThe Alignment Gym.\n\nThis is our weekly live space to:\n\n- Strengthen and clarify your vision\n- Practice getting into vibrational harmony on purpose\n- Get coaching and community support so your vision becomes real, not just "someday"\n\nWhen & where\n\nEvery Tuesday at 12 pm ET\nFirst session: Tuesday, March 31st\nLog in and join the session at: https://vibrationfit.com/alignment-gym\n\nPut this on your calendar as a recurring Tuesday lunch appointment and mark it "Busy." Treat it like a non-negotiable lunch with your future self.\n\nWho the Alignment Gym is for\n\nThe Alignment Gym is designed for members who have completed the Intensive, because we''ll be using those tools live, not reteaching them.\n\nIf you''ve already finished the Intensive:\n\n- Add the Alignment Gym to your calendar\n- Plan to be there live this Tuesday at 12 pm ET\n- Bring your vision and anything you''re currently creating\n\nIf you haven''t finished the Intensive yet:\n\nYou still have time to finish.\n\nLog in here: https://vibrationfit.com/auth/login\n\nWhen you complete the Intensive, you''ll be fully prepared to get the most from each Alignment Gym session.\n\nThink of the Intensive as your foundation and the Alignment Gym as your weekly practice. The more solid your foundation, the more powerfully you can use this space.\n\nWhy this matters\n\nMost people consume spiritual content and still feel stuck.\n\nThe Intensive gives you the framework.\nThe Alignment Gym gives you the reps.\n\nIf you want this next season of your life to actually look different, start by:\n\n1. Finishing your Intensive, and\n2. Showing up live on Tuesday at 12 pm ET.\n\nSee you in the Alignment Gym,\nJordan & Vanessa',

  '["firstName"]'::jsonb,
  '["Manual CRM blast to existing members"]'::jsonb
)
ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category,
  status = EXCLUDED.status, subject = EXCLUDED.subject, html_body = EXCLUDED.html_body,
  text_body = EXCLUDED.text_body, variables = EXCLUDED.variables,
  triggers = EXCLUDED.triggers, updated_at = NOW();
